throws DerivativeException, IntegratorException {

    // Sanity checks and initial setup
    sanityChecks(equations, t0, y0, t, y);
    setEquations(equations);
    resetEvaluations();
    final boolean forward = t > t0;

    // Create internal working arrays
    final int stages = c.length + 1;
    if (y != y0) {
        System.arraycopy(y0, 0, y, 0, y0.length);
    }
    final double[][] yDotK = new double[stages][y0.length];
    final double[] yTmp = new double[y0.length];

    // Setup interpolator
    AbstractStepInterpolator interpolator = (requiresDenseOutput() || (!eventsHandlersManager.isEmpty())) 
        ? new RungeKuttaStepInterpolator(prototype.copy()) 
        : new DummyStepInterpolator(yTmp, forward);

    interpolator.reinitialize(this, yTmp, yDotK, forward);
    interpolator.storeTime(t0);

    // Integration control
    stepStart = t0;
    double hNew = 0;
    boolean firstTime = true;
    for (StepHandler handler : stepHandlers) {
        handler.reset();
    }
    CombinedEventsManager manager = addEndTimeChecker(t0, t, eventsHandlersManager);
    boolean lastStep = false;

    // Main integration loop
    while (!lastStep) {
        interpolator.shift();
        double error = 0;

        for (boolean loop = true; loop;) {
            if (firstTime || !fsal) {
                // First stage
                computeDerivatives(stepStart, y, yDotK[0]);
            }

            if (firstTime) {
                final double[] scale = (vecAbsoluteTolerance == null) 
                    ? new double[y0.length] 
                    : vecAbsoluteTolerance;

                if (vecAbsoluteTolerance == null) {
                    java.util.Arrays.fill(scale, scalAbsoluteTolerance);
                }

                hNew = initializeStep(equations, forward, getOrder(), scale,
                                      stepStart, y, yDotK[0], yTmp, yDotK[1]);
                firstTime = false;
            }

            stepSize = hNew;

            // Next stages
            for (int k = 1; k < stages; ++k) {
                for (int j = 0; j < y0.length; ++j) {
                    double sum = a[k-1][0] * yDotK[0][j];
                    for (int l = 1; l < k; ++l) {
                        sum += a[k-1][l] * yDotK[l][j];
                    }
                    yTmp[j] = y[j] + stepSize * sum;
                }
                computeDerivatives(stepStart + c[k-1] * stepSize, yTmp, yDotK[k]);
            }

            // Estimate the state at the end of the step
            for (int j = 0; j < y0.length; ++j) {
                double sum = b[0] * yDotK[0][j];
                for (int l = 1; l < stages; ++l) {
                    sum += b[l] * yDotK[l][j];
                }
                yTmp[j] = y[j] + stepSize * sum;
            }

            // Estimate the error at the end of the step
            error = estimateError(yDotK, y, yTmp, stepSize);
            if (error <= 1.0) {
                // Handle discrete events
                interpolator.storeTime(stepStart + stepSize);
                if (manager.evaluateStep(interpolator)) {
                    final double dt = manager.getEventTime() - stepStart;
                    if (Math.abs(dt) <= Math.ulp(stepStart)) {
                        // Accept the step
                        loop = false;
                    } else {
                        // Reject the step to match next switch time
                        hNew = dt;
                    }
                } else {
                    // Accept the step
                    loop = false;
                }
            } else {
                // Reject the step and attempt to reduce error by step size control
                hNew = filterStep(stepSize * Math.min(maxGrowth, Math.max(minReduction, safety * Math.pow(error, exp))), forward, false);
            }
        }

        // Step accepted
        final double nextStep = stepStart + stepSize;
        System.arraycopy(yTmp, 0, y, 0, y0.length);
        manager.stepAccepted(nextStep, y);
        lastStep = manager.stop();

        // Provide step data to handlers
        interpolator.storeTime(nextStep);
        for (StepHandler handler : stepHandlers) {
            handler.handleStep(interpolator, lastStep);
        }
        stepStart = nextStep;

        // Handle fsal
        if (fsal) {
            System.arraycopy(yDotK[stages - 1], 0, yDotK[0], 0, y0.length);
        }

        // Event handling
        if (manager.reset(stepStart, y) && !lastStep) {
            computeDerivatives(stepStart, y, yDotK[0]);
        }

        if (!lastStep) {
            stepSize = filterStep(stepSize, forward, true);
            final double scaledH = stepSize * Math.min(maxGrowth, Math.max(minReduction, safety * Math.pow(error, exp)));
            final double nextT = stepStart + scaledH;
            hNew = filterStep(scaledH, forward, (forward ? (nextT >= t) : (nextT <= t)));
        }
    }

    resetInternalState();
    return stepStart;
}
